export class GameServer extends DurableObject {
  async fetch(request) {
    let p = new URL(request.url).pathname;
    if (p === '/' || p === '') p = '/index.html';
    const f = FILES[p] || FILES['/index.html'];
    return new Response(f.body, { headers: { 'content-type': f.ct, 'cache-control': 'no-cache' } });
  }
}
